const AWS = require('aws-sdk');
const cloudfront = new AWS.CloudFront();

exports.handler = async (event) => {
  const request = event.Records[0].cf.request;
  const response = event.Records[0].cf.response;

  // Get the custom headers set by the viewer request function
  const injectionPoints = request.headers['injection-points'];
  const content = request.headers['content'];

  // Parse the HTML response and insert the content at the specified locations
  const htmlResponse = await cloudfront.getObject({
    Bucket: 'my-bucket',
    Key: 'index.html'
  }).promise();

  const parsedHtml = parseHTML(htmlResponse.Body);

  for (const injectionPoint of injectionPoints) {
    const location = injectionPoint.split(':');
    const tagName = location[0];
    const attributeName = location[1];
    const attributeValue = content;

    // Insert the content at the specified location
    parsedHtml.querySelector(`${tagName}[${attributeName}="${attributeValue}"]`).innerHTML = content;
  }

  // Return the modified HTML response
  return {
    status: '200',
    headers: {
      'Content-Type': 'text/html'
    },
    body: parsedHtml.outerHTML
  };
};

function parseHTML(html) {
  const parser = new DOMParser();
  return parser.parseFromString(html, 'text/html');
}